const iconPaths = {
  home: '<path d="M3 11l9-8 9 8M5 10v10h14V10" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/>',
  events: '<rect x="3" y="5" width="18" height="16" rx="3" stroke="currentColor" stroke-width="1.8"/><path d="M3 10h18M8 3v4M16 3v4" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/>',
  vortex: '<circle cx="12" cy="12" r="8" stroke="currentColor" stroke-width="1.8"/><circle cx="12" cy="12" r="2.4" fill="currentColor"/><path d="M12 2v3M12 19v3" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/>',
  messages: '<path d="M21 11.5a8.5 8.5 0 01-12.4 7.6L3 21l1.9-5.7A8.5 8.5 0 1112.5 20" stroke="currentColor" stroke-width="1.8" stroke-linejoin="round"/>',
  notifications: '<path d="M18 8a6 6 0 10-12 0c0 7-3 9-3 9h18s-3-2-3-9M13.7 21a2 2 0 01-3.4 0" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/>',
  profile: '<circle cx="12" cy="8" r="4" stroke="currentColor" stroke-width="1.8"/><path d="M4 20c0-4 3.6-6.5 8-6.5s8 2.5 8 6.5" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/>',
  settings: '<circle cx="12" cy="12" r="3" stroke="currentColor" stroke-width="1.8"/><path d="M19.4 15a1.65 1.65 0 00.33 1.82l.06.06a2 2 0 11-2.83 2.83l-.06-.06a1.65 1.65 0 00-1.82-.33 1.65 1.65 0 00-1 1.51V21a2 2 0 01-4 0v-.09a1.65 1.65 0 00-1-1.51 1.65 1.65 0 00-1.82.33l-.06.06a2 2 0 11-2.83-2.83l.06-.06a1.65 1.65 0 00.33-1.82 1.65 1.65 0 00-1.51-1H3a2 2 0 010-4h.09a1.65 1.65 0 001.51-1 1.65 1.65 0 00-.33-1.82l-.06-.06a2 2 0 112.83-2.83l.06.06a1.65 1.65 0 001.82.33H9a1.65 1.65 0 001-1.51V3a2 2 0 014 0v.09a1.65 1.65 0 001 1.51 1.65 1.65 0 001.82-.33l.06-.06a2 2 0 112.83 2.83l-.06.06a1.65 1.65 0 00-.33 1.82V9a1.65 1.65 0 001.51 1H21a2 2 0 010 4h-.09a1.65 1.65 0 00-1.51 1z" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"/>',
  premium: '<path d="M5 18h14l1.5-9-5 3-3.5-6-3.5 6-5-3L5 18z" stroke="currentColor" stroke-width="1.8" stroke-linejoin="round"/>',
  creator: '<path d="M4 19V6a2 2 0 012-2h9l5 5v10a2 2 0 01-2 2H6a2 2 0 01-2-2z" stroke="currentColor" stroke-width="1.8"/><path d="M8 13l2.5 2.5L16 10" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/>',
  brand: '<path d="M3 9l9-6 9 6-9 6-9-6zM3 9v6l9 6 9-6V9" stroke="currentColor" stroke-width="1.8" stroke-linejoin="round"/>',
  admin: '<path d="M12 2l8 4v6c0 5-3.4 8.4-8 10-4.6-1.6-8-5-8-10V6l8-4z" stroke="currentColor" stroke-width="1.8" stroke-linejoin="round"/>',
  search: '<circle cx="11" cy="11" r="7" stroke="currentColor" stroke-width="1.8"/><path d="M21 21l-4.3-4.3" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/>',
};

function Icon({ name }) { return <svg viewBox="0 0 24 24" fill="none" aria-hidden="true" dangerouslySetInnerHTML={{ __html: iconPaths[name] || '' }} />; }
function initials(name = '') { return name.split(' ').map((part) => part[0]).join('').slice(0, 2).toUpperCase() || 'P'; }
function Avatar({ children, size = 'md' }) { return <span className={`avatar size-${size}`}>{children}</span>; }
function timeLabel(value) { return value?.toDate ? value.toDate().toLocaleDateString() : 'Now'; }
function firebaseMessage(error) { return error?.message?.replace('Firebase: ', '') || 'Something went wrong. Please try again.'; }
function formatMoney(amountMinor, currency = 'GBP') {
  if (!Number.isFinite(amountMinor)) return 'Custom price';
  return new Intl.NumberFormat('en-GB', { style: 'currency', currency }).format(amountMinor / 100);
}
function routeHandleQuery(route) { return new URLSearchParams(route.split('?')[1] || '').get('handle') || ''; }
function normalizedQueryHandle(value = '') { return value.replace(/^@/, '').trim().toLowerCase(); }

export const EVENTS_UNAVAILABLE_MESSAGE = 'Events are temporarily unavailable. Please try again shortly.';
export const PROFILE_HANDLE_PLACEHOLDER = 'Choose your unique handle';
const eventRegions = ['World', 'Nearby', 'United Kingdom', 'Europe', 'Africa', 'Americas', 'Asia'];
const eventCategories = ['All', 'World', 'Weather', 'Transport', 'Public safety', 'Politics', 'Sport', 'Culture', 'Technology'];
const contributionTabs = ['Overview', 'Timeline', 'Reports', 'Updates', 'Signals', 'Conversation', 'Evidence', 'Sources', 'Contributors', 'Related Events'];

function Brand() { return <a href="#/" className="brand" aria-label="Portal home"><span className="brand-mark"><svg viewBox="0 0 24 24" fill="none"><path d="M12 2v20M2 12h20" stroke="#fff" strokeWidth="2" strokeLinecap="round" /><circle cx="12" cy="12" r="4" stroke="#fff" strokeWidth="2" /></svg></span><span className="brand-name desktop-only">Portal</span></a>; }
function NavLink({ route, current }) { const active = route.path === '/' ? current === '/' : current === route.path || current.startsWith(`${route.path}?`); return <a href={`#${route.path}`} className="nav-item" aria-current={active ? 'page' : undefined}><Icon name={route.icon} /><span>{route.label}</span></a>; }

function Sidebar({ current, onCreate }) {
  return <nav className="sidebar desktop-only" aria-label="Primary"><Brand /><div className="nav-group">{routes.map((route) => <NavLink key={route.path} route={route} current={current} />)}</div><button className="create-btn" onClick={onCreate} aria-haspopup="dialog"><span>+</span>Create</button><div className="nav-group secondary-nav"><div className="eyebrow nav-label">More</div>{secondaryRoutes.map((route) => <NavLink key={route.path} route={route} current={current} />)}</div></nav>;
}
function Topbar({ profile }) { return <header className="topbar mobile-only"><Brand /><div className="topbar-actions"><a aria-label="Open settings" href="#/settings"><Avatar size="sm">{initials(profile?.displayName)}</Avatar></a></div></header>; }
function BottomNav({ current }) { return <nav className="bottom-nav mobile-only" aria-label="Primary">{['/', '/events', '/vortex', '/marketplace', '/profile'].map((path) => { const route = routes.find((item) => item.path === path); const active = path === '/' ? current === '/' : current === path || current.startsWith(`${path}?`); return <a key={path} href={`#${path}`} className={`bnav-item ${path === '/vortex' ? 'vortex-center' : ''}`} aria-current={active ? 'page' : undefined}><Icon name={route.icon} /><span>{route.label}</span></a>; })}</nav>; }

function Section({ title, link, children }) { return <section><div className="section-header"><h2>{title}</h2>{link ? <a className="see-all" href={link}>See all</a> : null}</div><div className="section-body">{children}</div></section>; }
function Loading({ label = 'Loading Portal...' }) { return <div className="glass card empty-state"><div className="loader" /><p className="body-sm">{label}</p></div>; }
function ErrorState({ message }) { return <div className="glass card empty-state"><h2 className="display-md">Portal could not load this</h2><p className="body-sm">{message}</p></div>; }

function EventCard({ event, follow, onFollow }) {
  return <article className="glass card interactive event-card memory-event-card"><div className="inline-meta"><span className={`event-status ${(event.status || '').toLowerCase()}`}>{event.status}</span>{event.confidenceLabel ? <span className="source-chip">{event.confidenceLabel}</span> : null}</div><a href={`#/events/${event.id}`}><strong>{event.title}</strong></a><span className="body-sm">{event.summary}</span><div className="metrics"><span>{event.locationSummary || event.primaryLocation || event.region || 'World'}</span><span>{event.sourceCount || 0} sources</span><span>{event.contributorCount || 0} contributors</span><span>{timeLabel(event.lastMeaningfulUpdateAt || event.updatedAt)}</span></div>{onFollow ? <button className="btn btn-secondary btn-sm" type="button" onClick={() => onFollow(event.id, !follow)}>{follow ? 'Following' : 'Follow event'}</button> : null}</article>;
}

function EventCollection({ events, loading, error, empty, onFollow, following = new Set() }) {
  if (loading) return <Loading label="Finding events..." />;
  if (error) return <ErrorState message={error} />;
  if (!events.length) return <div className="glass card empty-state"><h2 className="display-md">{empty}</h2><p className="body-sm">Create a report or event to begin building Portal&apos;s living memory.</p></div>;
  return <div className="event-grid">{events.map((event) => <EventCard key={event.id} event={event} follow={following.has(event.id)} onFollow={onFollow} />)}</div>;
}

function PostCard({ post, echoed, onEcho, onQuote }) {
  const [menuOpen, setMenuOpen] = useState(false); const author = post.authorHandle || post.handle || 'portal member'; const name = post.authorDisplayName || post.displayName || author;
  return <article className="glass card post-card"><div className="post-meta"><Avatar size="sm">{initials(name)}</Avatar><div><strong>{name}</strong><span>@{author}</span></div><button className="icon-button" type="button" aria-label="Post actions" onClick={() => setMenuOpen(!menuOpen)}>•••</button></div>{post.echoedByHandle ? <p className="echo-context">@{post.echoedByHandle} echoed</p> : null}<a className="post-body post-link" href={`#/posts/${post.id}`}>{post.body || post.text || post.content}</a><div className="post-footer"><span>{timeLabel(post.publishedAt || post.createdAt)}</span><span>{post.echoCount || 0} Echoes</span><div className="post-actions"><button className={`text-action ${echoed ? 'active' : ''}`} type="button" onClick={() => onEcho(post.id, !echoed)} aria-pressed={echoed}>{echoed ? 'Echoed' : 'Echo'}</button><button className="text-action" type="button" onClick={() => onQuote(post)}>Quote Echo</button></div></div>{menuOpen ? <div className="action-menu" role="menu"><button type="button" role="menuitem" onClick={() => { onEcho(post.id, !echoed); setMenuOpen(false); }}>{echoed ? 'Undo Echo' : 'Echo'}</button><button type="button" role="menuitem" onClick={() => { onQuote(post); setMenuOpen(false); }}>Quote Echo</button><button type="button" role="menuitem" onClick={() => setMenuOpen(false)}>Cancel</button></div> : null}</article>;
}

function QuoteEchoComposer({ post, onClose, onSubmit, busy }) {
  const [quoteText, setQuoteText] = useState('');
  return <div className="modal-overlay" role="dialog" aria-modal="true" aria-labelledby="quoteEchoTitle"><div className="modal form-modal" onMouseDown={(event) => event.stopPropagation()}><div className="modal-head"><div><h2 id="quoteEchoTitle">Quote Echo</h2><p className="body-sm">Add your perspective without losing the original Post.</p></div><button className="modal-close" type="button" onClick={onClose} aria-label="Close">×</button></div><form className="form-stack" onSubmit={(event) => { event.preventDefault(); onSubmit(quoteText); }}><textarea value={quoteText} onChange={(event) => setQuoteText(event.target.value)} maxLength="1000" placeholder="What do you make of this?" required /><a className="glass card embedded-post" href={`#/posts/${post.id}`}><strong>@{post.authorHandle || post.handle || 'portal member'}</strong><p>{post.body || post.text || post.content}</p></a><div className="form-actions"><button className="btn btn-primary" disabled={busy || !quoteText.trim()}>{busy ? 'Publishing...' : 'Publish Quote Echo'}</button><button className="btn btn-secondary" type="button" onClick={onClose} disabled={busy}>Cancel</button></div></form></div></div>;
}

function Home({ posts, echoedPostIds, onEcho, onQuote, onCreatePost }) {
  const recentPosts = posts.slice(0, 8);
  const suggestedCreators = [...new Map(posts.map((post) => [post.authorUid || post.createdBy || post.authorHandle, post])).values()].filter(Boolean).slice(0, 4);
  return <div className="page home-page"><div className="welcome-head"><div><h1 className="display-xl">Humanity&apos;s living memory</h1><p className="body-md">Posts, Reports and creator activity from the people you follow.</p></div><button className="btn btn-primary" type="button" onClick={onCreatePost}>Publish Post</button></div><div className="home-layout"><section className="home-timeline"><Section title="Your timeline"><div className="stack home-feed">{recentPosts.length ? recentPosts.map((post) => <PostCard key={post.id} post={post} echoed={echoedPostIds.has(post.id)} onEcho={onEcho} onQuote={onQuote} />) : <div className="glass card empty-state compact-empty"><h2 className="display-md">Your timeline is quiet</h2><p className="body-sm">Publish a Post or follow creators to bring this page to life.</p><button className="btn btn-primary btn-sm" type="button" onClick={onCreatePost}>Publish Post</button></div>}</div></Section><Section title="Recent Reports"><div className="glass card empty-state compact-empty"><h2 className="display-md">No Reports in your timeline yet</h2><p className="body-sm">Reports from creators and sources you follow will appear here when they publish evidence.</p></div></Section></section><aside className="home-widgets" aria-label="Creator activity"><Section title="Suggested creators">{suggestedCreators.length ? <div className="creator-grid">{suggestedCreators.map((post) => { const name = post.authorDisplayName || post.authorHandle || 'Portal member'; return <article className="glass card creator-card" key={post.authorUid || post.createdBy || post.authorHandle || post.id}><Avatar size="sm">{initials(name)}</Avatar><div><strong>{name}</strong><p className="body-sm">@{post.authorHandle || post.handle || 'portal'}</p></div><a className="btn btn-secondary btn-sm" href="#/vortex">Discover</a></article>; })}</div> : <div className="glass card empty-state compact-empty"><h2 className="display-md">No creator suggestions yet</h2><p className="body-sm">Portal will suggest people when public creator activity exists.</p></div>}</Section><Section title="Creator activity"><div className="glass card empty-state compact-empty"><h2 className="display-md">Nothing new from followed creators</h2><p className="body-sm">Fresh Posts and Reports from people you follow will collect here.</p></div></Section></aside></div></div>;
}

function PostComposer({ onClose, onSubmit, busy }) { const [body, setBody] = useState(''); return <div className="modal-overlay" role="dialog" aria-modal="true" aria-labelledby="postComposerTitle"><div className="modal form-modal" onMouseDown={(event) => event.stopPropagation()}><div className="modal-head"><h2 id="postComposerTitle">Publish a Post</h2><button className="modal-close" type="button" onClick={onClose} aria-label="Close">×</button></div><form className="form-stack" onSubmit={(event) => { event.preventDefault(); onSubmit(body); }}><textarea value={body} onChange={(event) => setBody(event.target.value)} maxLength="2000" placeholder="What is happening in your corner of the universe?" required /><div className="form-actions"><button className="btn btn-primary" disabled={busy || !body.trim()}>{busy ? 'Publishing...' : 'Publish Post'}</button><button className="btn btn-secondary" type="button" onClick={onClose}>Cancel</button></div></form></div></div>; }

function PostDetail({ postId, echoed, onEcho, onQuote }) {
  const [post, setPost] = useState(null); const [loading, setLoading] = useState(true); const [error, setError] = useState('');
  useEffect(() => { const stop = observePost(postId, (snapshot) => { setPost(snapshot.exists() ? { id: snapshot.id, ...snapshot.data() } : null); setLoading(false); }, (reason) => { setError(firebaseMessage(reason)); setLoading(false); }); return stop; }, [postId]);
  if (loading) return <Loading label="Opening Post..." />;
  if (error) return <ErrorState message={error} />;
  if (!post || post.deleted || post.visibility !== 'public') return <ErrorState message="This Post is unavailable." />;
  return <div className="page"><a className="see-all" href="#/">Back to Home</a><div><h1 className="display-xl">Post</h1><p className="body-md">The original stays with its author. Echoes carry it further.</p></div><PostCard post={post} echoed={echoed} onEcho={onEcho} onQuote={onQuote} /></div>;
}

function EventForm({ initial, events, onSubmit, onCancel, busy }) {
  const [values, setValues] = useState(initial || { title: '', summary: '', status: 'Developing', parentEventId: '' });
  const [error, setError] = useState('');
  function submit(event) { event.preventDefault(); if (values.title.trim().length < 3 || values.summary.trim().length < 12) { setError('Use a clear title and a summary of at least 12 characters.'); return; } onSubmit(values); }
  return <form className="form-stack" onSubmit={submit}><label>Event name<input value={values.title} onChange={(event) => setValues({ ...values, title: event.target.value })} maxLength="120" required /></label><label>Summary<textarea value={values.summary} onChange={(event) => setValues({ ...values, summary: event.target.value })} maxLength="1000" required /></label><label>Status<select value={values.status} onChange={(event) => setValues({ ...values, status: event.target.value })}>{eventStatuses.map((status) => <option key={status}>{status}</option>)}</select></label><label>Parent event<select value={values.parentEventId} onChange={(event) => setValues({ ...values, parentEventId: event.target.value })}><option value="">No parent event</option>{events.filter((event) => event.id !== initial?.id).map((event) => <option value={event.id} key={event.id}>{event.title}</option>)}</select></label>{error ? <p className="form-error" role="alert">{error}</p> : null}<div className="form-actions"><button className="btn btn-primary" disabled={busy}>{busy ? 'Saving...' : 'Save event'}</button>{onCancel ? <button className="btn btn-secondary" type="button" onClick={onCancel}>Cancel</button> : null}</div></form>;
}

function Events({ user, eventState, onFollow, following, onCreate }) {
  const [status, setStatus] = useState('All'); const [region, setRegion] = useState('World'); const [category, setCategory] = useState('All'); const [time, setTime] = useState('Active'); const [view, setView] = useState('List');
  const filtered = eventState.events.filter((event) => status === 'All' || event.status === status).filter((event) => region === 'World' || event.region === region || event.country === region || event.geographicScope === region).filter((event) => category === 'All' || event.category === category).filter((event) => time !== 'Followed' || following.has(event.id)).filter((event) => time !== 'Active' || ['Breaking', 'Developing', 'Confirmed'].includes(event.status));
  const activeGlobalEvents = eventState.events.filter((event) => ['Breaking', 'Developing', 'Confirmed'].includes(event.status)).slice(0, 8);
  return <div className="page events-page"><div className="welcome-head"><div><h1 className="display-xl">Events</h1><p className="body-md">Real happenings, organised by evidence, sources, status and relationship.</p></div><button type="button" className="btn btn-primary" onClick={onCreate}>Create event</button></div><Section title="Happening around the world"><div className="chip-row subtle-row">{eventRegions.map((item) => <button type="button" className={`chip ${region === item ? 'active' : ''}`} onClick={() => setRegion(item)} key={item}>{item}</button>)}</div><EventCollection events={activeGlobalEvents} loading={eventState.loading} error={eventState.error ? EVENTS_UNAVAILABLE_MESSAGE : ''} empty="No active global Events yet" onFollow={onFollow} following={following} /></Section><Section title="Browse Events"><div className="filter-grid"><div><span className="eyebrow">Status</span><div className="chip-row">{['All', ...eventStatuses].map((item) => <button type="button" className={`chip ${status === item ? 'active' : ''}`} onClick={() => setStatus(item)} key={item}>{item}</button>)}</div></div><div><span className="eyebrow">Category</span><div className="chip-row">{eventCategories.map((item) => <button type="button" className={`chip ${category === item ? 'active' : ''}`} onClick={() => setCategory(item)} key={item}>{item}</button>)}</div></div><div><span className="eyebrow">Time and view</span><div className="chip-row">{['Active', '24h', '7d', 'Followed'].map((item) => <button type="button" className={`chip ${time === item ? 'active' : ''}`} onClick={() => setTime(item)} key={item}>{item}</button>)}{['List', 'World view'].map((item) => <button type="button" className={`chip ${view === item ? 'active' : ''}`} onClick={() => setView(item)} key={item}>{item}</button>)}</div></div></div></Section>{view === 'World view' ? <div className="glass card global-map-placeholder"><h2 className="display-md">World view</h2><p className="body-sm">Map rendering will appear when location-rich Events are available. The list below remains the source of truth.</p></div> : null}<Section title="Events happening now"><EventCollection events={filtered} loading={eventState.loading} error={eventState.error ? EVENTS_UNAVAILABLE_MESSAGE : ''} empty="No matching Events" onFollow={onFollow} following={following} /></Section><p className="body-sm">Signed in as {user.email}</p></div>;
}

function EventDetail({ eventId, user, events, onFollow, following }) {
  const [event, setEvent] = useState(null); const [reports, setReports] = useState([]); const [sources, setSources] = useState([]); const [contributions, setContributions] = useState([]); const [history, setHistory] = useState([]); const [timeline, setTimeline] = useState([]); const [activeTab, setActiveTab] = useState('Overview'); const [replayIndex, setReplayIndex] = useState(null); const [loading, setLoading] = useState(true); const [error, setError] = useState(''); const [editing, setEditing] = useState(false); const [busy, setBusy] = useState(false); const [report, setReport] = useState({ body: '', sourceType: 'Eyewitness' }); const [contribution, setContribution] = useState({ type: 'Update', body: '' });
  useEffect(() => { const stop = observeEvent(eventId, (snapshot) => { setEvent(snapshot.exists() ? { id: snapshot.id, ...snapshot.data() } : null); setLoading(false); }, (reason) => { setError(firebaseMessage(reason)); setLoading(false); }); return stop; }, [eventId]);
  useEffect(() => { const stop = observeReports(eventId, (snapshot) => setReports(snapshot.docs.map((item) => ({ id: item.id, ...item.data() }))), (reason) => setError(firebaseMessage(reason))); return stop; }, [eventId]);
  useEffect(() => { const stop = observeEventSources(eventId, (snapshot) => setSources(snapshot.docs.map((item) => ({ id: item.id, ...item.data() }))), (reason) => setError(firebaseMessage(reason))); return stop; }, [eventId]);
  useEffect(() => { const stop = observeEventContributions(eventId, (snapshot) => setContributions(snapshot.docs.map((item) => ({ id: item.id, ...item.data() }))), (reason) => setError(firebaseMessage(reason))); return stop; }, [eventId]);
  useEffect(() => { const stop = observeEventStatusHistory(eventId, (snapshot) => setHistory(snapshot.docs.map((item) => ({ id: item.id, ...item.data() }))), (reason) => setError(firebaseMessage(reason))); return stop; }, [eventId]);
  useEffect(() => { const stop = observeEventTimeline(eventId, (snapshot) => setTimeline(snapshot.docs.map((item) => ({ id: item.id, ...item.data() }))), (reason) => setError(firebaseMessage(reason))); return stop; }, [eventId]);
  async function save(values) { setBusy(true); try { await updatePortalEvent(eventId, values); setEditing(false); } catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); } }
  async function archive() { if (!window.confirm('Archive this event? It will disappear from the live event list.')) return; setBusy(true); try { await archivePortalEvent(eventId); window.location.hash = '#/events'; } catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); } }
  async function submitReport(item) { item.preventDefault(); if (report.body.trim().length < 12 || busy) return; setBusy(true); try { await createPortalReport(user, eventId, report); setReport({ body: '', sourceType: 'Eyewitness' }); } catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); } }
  async function submitContribution(item) { item.preventDefault(); if (contribution.body.trim().length < 3 || busy) return; setBusy(true); try { await submitPortalEventContribution(eventId, contribution.type, contribution.body); setContribution({ type: 'Update', body: '' }); } catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); } }
  if (loading) return <Loading label="Opening event..." />; if (error) return <ErrorState message={error} />; if (!event) return <ErrorState message="This event no longer exists or you do not have access to it." />;
  const owner = event.createdBy === user.uid;
  const replayEntries = replayIndex == null ? timeline : timeline.slice(0, replayIndex + 1); const replayEntry = replayIndex == null ? timeline[timeline.length - 1] : timeline[replayIndex];
  const tabEntries = activeTab === 'Timeline' ? timeline : activeTab === 'Reports' ? timeline.filter((item) => item.entryType === 'Report') : activeTab === 'Updates' ? timeline.filter((item) => item.entryType === 'Update') : activeTab === 'Signals' ? timeline.filter((item) => item.entryType === 'Signal') : activeTab === 'Conversation' ? timeline.filter((item) => ['Post', 'Quote Echo'].includes(item.entryType)) : activeTab === 'Evidence' ? timeline.filter((item) => ['Report', 'media', 'official_notice', 'structured_fact'].includes(item.entryType)) : timeline;
  return <div className="page"><a className="see-all" href="#/events">Back to events</a><div className={`glass card hero-event ${event.status === 'Historic' ? 'historic-event' : ''}`}><div className="inline-meta"><span className={`event-status ${(event.status || '').toLowerCase()}`}>{event.status}</span>{event.confidenceLabel ? <span className="source-chip">{event.confidenceLabel}</span> : null}<span className="source-chip">{event.category || 'World'}</span></div><h1>{event.title}</h1><p className="body-md">{event.summary}</p><div className="hero-meta"><button className="btn btn-primary btn-sm" onClick={() => onFollow(event.id, !following)}>{following ? 'Following' : 'Follow event'}</button>{owner ? <><button className="btn btn-secondary btn-sm" onClick={() => setEditing(!editing)}>Edit</button><button className="btn btn-secondary btn-sm" disabled={busy} onClick={archive}>Archive</button></> : null}</div><div className="metrics"><span>{event.locationSummary || event.primaryLocation || 'World'}</span><span>{event.sourceCount || sources.length} sources</span><span>{event.contributorCount || contributions.length} contributors</span><span>Last verified {timeLabel(event.lastMeaningfulUpdateAt || event.updatedAt)}</span></div></div>{editing ? <section className="glass card"><h2 className="display-md">Edit event</h2><EventForm initial={event} events={events} onSubmit={save} onCancel={() => setEditing(false)} busy={busy} /></section> : null}<Section title={event.status === 'Historic' ? 'Historical replay' : 'Live chronology'}><div className="glass card replay-panel"><div className="form-actions"><button className="btn btn-secondary btn-sm" type="button" onClick={() => setReplayIndex(0)} disabled={!timeline.length}>Start</button><button className="btn btn-secondary btn-sm" type="button" onClick={() => setReplayIndex((current) => Math.max(0, (current ?? timeline.length - 1) - 1))} disabled={!timeline.length}>Previous update</button><button className="btn btn-secondary btn-sm" type="button" onClick={() => setReplayIndex((current) => Math.min(timeline.length - 1, (current ?? timeline.length - 1) + 1))} disabled={!timeline.length}>Next update</button><button className="btn btn-primary btn-sm" type="button" onClick={() => setReplayIndex(null)}>Final outcome</button></div><p className="body-sm">{replayEntry ? `Viewing ${replayEntries.length} of ${timeline.length} entries. Happened ${timeLabel(replayEntry.eventTimestamp)} · Added to Portal ${timeLabel(replayEntry.ingestionTimestamp || replayEntry.createdAt)}.` : 'No canonical timeline entries yet.'}</p></div></Section><Section title="Add to this Event"><form className="form-stack glass card" onSubmit={submitContribution}><label>Contribution type<select value={contribution.type} onChange={(item) => setContribution({ ...contribution, type: item.target.value })}>{['Update', 'Post', 'Signal', 'Report', 'Correction', 'Source'].map((item) => <option key={item}>{item}</option>)}</select></label><label>Contribution<textarea value={contribution.body} onChange={(item) => setContribution({ ...contribution, body: item.target.value })} maxLength="2000" required /></label><button className="btn btn-primary" disabled={busy}>{busy ? 'Adding...' : 'Add to Event record'}</button></form></Section><Section title="Event record"><div className="tabs" role="tablist">{contributionTabs.map((item) => <button className={`tab ${activeTab === item ? 'active' : ''}`} role="tab" aria-selected={activeTab === item} onClick={() => setActiveTab(item)} key={item} type="button">{item}</button>)}</div>{activeTab === 'Overview' ? <div className="event-overview-grid"><div className="glass card"><h2 className="display-md">Final verified summary</h2><p className="body-sm">{event.finalSummary || event.summary}</p></div><div className="glass card"><h2 className="display-md">Current snapshot</h2><p className="body-sm">{event.currentSnapshot ? JSON.stringify(event.currentSnapshot) : 'No structured snapshot yet.'}</p></div><div className="glass card"><h2 className="display-md">Archive state</h2><p className="body-sm">{reports.length} reports · {history.length} status entries · {timeline.length} chronology entries.</p></div><div className="glass card"><h2 className="display-md">Relationships</h2><p className="body-sm">{event.parentEventId ? `Part of ${event.parentEventId}` : 'No parent Event linked yet.'}</p></div></div> : activeTab === 'Sources' ? <div className="stack">{sources.length ? sources.map((source) => <article className="glass card timeline-entry" key={source.id}><span className="source-chip">{source.provider}</span><strong>{source.title}</strong><p className="body-sm">{source.summary || 'Source no longer available'}</p>{source.sourceUrl ? <a className="see-all" href={source.sourceUrl} target="_blank" rel="noreferrer">Open source</a> : <span className="body-sm">Source no longer available</span>}</article>) : <div className="glass card empty-state"><p className="body-sm">No source records yet.</p></div>}</div> : activeTab === 'Contributors' ? <div className="stack">{contributions.length ? contributions.map((item) => <article className="glass card timeline-entry" key={item.id}><span className="source-chip">{item.contributionType}</span><strong>@{item.authorHandle || 'portal member'}</strong><p className="body-sm">{item.body}</p></article>) : <div className="glass card empty-state"><p className="body-sm">No contributors yet.</p></div>}</div> : activeTab === 'Related Events' ? <div className="stack">{events.filter((item) => event.relatedEventIds?.includes(item.id) || item.parentEventId === event.id || item.id === event.parentEventId).map((item) => <EventCard key={item.id} event={item} follow={false} onFollow={null} />)}</div> : <TimelineList entries={tabEntries} />}</Section><Section title="Reports"><form className="form-stack glass card" onSubmit={submitReport}><label>What happened?<textarea value={report.body} onChange={(item) => setReport({ ...report, body: item.target.value })} maxLength="2000" required /></label><label>Source type<select value={report.sourceType} onChange={(item) => setReport({ ...report, sourceType: item.target.value })}>{sourceTypes.map((source) => <option key={source}>{source}</option>)}</select></label><button className="btn btn-secondary" disabled={busy}>{busy ? 'Adding report...' : 'Add report'}</button></form></Section></div>;
}

function TimelineList({ entries }) {
  if (!entries.length) return <div className="glass card empty-state"><p className="body-sm">No entries in this view yet.</p></div>;
  return <div className="timeline canonical-timeline">{entries.map((entry) => <article className="timeline-row timeline-entry" key={entry.id || entry.entryId}><time>{timeLabel(entry.eventTimestamp || entry.createdAt)}</time><div><div className="inline-meta"><span className="source-chip">{entry.entryType}</span><span className="source-chip">{entry.confidenceLabel || 'Emerging'}</span>{entry.correctionTargetId ? <span className="source-chip">Correction</span> : null}</div><p className="body-sm">{entry.content || entry.summary || entry.body}</p><p className="body-sm">Added to Portal {timeLabel(entry.ingestionTimestamp || entry.createdAt)}{entry.handleSnapshot ? ` by @${entry.handleSnapshot}` : entry.source ? ` from ${entry.source}` : ''}</p>{entry.sourceAttribution?.sourceUrl ? <a className="see-all" href={entry.sourceAttribution.sourceUrl} target="_blank" rel="noreferrer">Source</a> : null}</div></article>)}</div>;
}

function Vortex({ entries, loading, error, following, onFollow }) {
  const [term, setTerm] = useState(''); const [tab, setTab] = useState('All');
  const results = entries.filter((entry) => `${entry.title} ${entry.displaySummary} ${entry.entryType} ${entry.status || ''} ${entry.locationSummary || ''}`.toLowerCase().includes(term.toLowerCase())).filter((entry) => tab === 'Following' ? entry.entryType === 'Event' && following.has(entry.sourceId) : tab === 'Live' ? entry.entryType === 'Event' && ['Breaking', 'Developing'].includes(entry.status) : tab === 'Historic' ? entry.entryType === 'Event' && entry.status === 'Historic' : tab === 'All' || (tab === 'Quote Echoes' ? entry.entryType === 'Quote Echo' : entry.entryType === tab.slice(0, -1)));
  return <div className="page vortex-page"><div><h1 className="display-xl">Vortex</h1><p className="body-md">The rocket through Portal&apos;s universe: search, jump and trace how events connect.</p></div><div className="vortex-orb-field" aria-hidden="true"><span className="label">Travel through humanity&apos;s knowledge</span></div><div className="vortex-search-wrap"><label className="glass field vortex-field"><Icon name="search" /><input value={term} onChange={(event) => setTerm(event.target.value)} type="search" placeholder="Search Events, teams, places, sources, Signals or Posts..." /></label></div><div className="tabs" role="tablist">{['All', 'Live', 'Events', 'Historic', 'Signals', 'Reports', 'Posts', 'Quote Echoes', 'Following'].map((item) => <button className={`tab ${tab === item ? 'active' : ''}`} role="tab" aria-selected={tab === item} onClick={() => setTab(item)} key={item} type="button">{item}</button>)}</div>{loading ? <Loading label="Scanning the Vortex..." /> : error ? <ErrorState message="The Vortex is temporarily unavailable. Please try again shortly." /> : !results.length ? <div className="glass card empty-state"><h2 className="display-md">The Vortex found nothing.</h2><p className="body-sm">Either it never happened or everyone is pretending.</p></div> : <div className="stack vortex-feed">{results.map((entry) => <VortexEntry key={entry.entryId} entry={entry} following={following.has(entry.sourceId)} onFollow={onFollow} />)}</div>}</div>;
}

function VortexEntry({ entry, following, onFollow }) {
  const eventEntry = entry.entryType === 'Event'; const href = eventEntry ? `#/events/${entry.sourceId}` : entry.parentEventId ? `#/events/${entry.parentEventId}` : null;
  return <article className="glass card vortex-entry"><div className="inline-meta"><span className={`entry-type ${entry.entryType.toLowerCase()}`}>{entry.entryType}</span>{entry.status ? <span className="source-chip">{entry.status}</span> : null}<span className="body-sm">Active {timeLabel(entry.latestActivityAt)}</span></div>{href ? <a href={href}><h2 className="display-md">{entry.title}</h2></a> : <h2 className="display-md">{entry.title}</h2>}<p className="body-sm">{entry.displaySummary}</p><div className="metrics"><span>{entry.contributionCount || 0} contributions</span><span>{entry.reportCount || 0} reports</span><span>{entry.sourceCount || 0} sources</span></div>{eventEntry ? <button className="btn btn-secondary btn-sm" type="button" onClick={() => onFollow(entry.sourceId, !following)}>{following ? 'Following' : 'Follow event'}</button> : null}</article>;
}

function HandleMarketplace({ user, route }) {
  const initialHandle = normalizedQueryHandle(routeHandleQuery(route));
  const [handle, setHandle] = useState(initialHandle);
  const [result, setResult] = useState(null);
  const [step, setStep] = useState(initialHandle ? 'detail' : 'search');
  const [purchase, setPurchase] = useState(null);
  const [paymentNotice, setPaymentNotice] = useState('');
  const [error, setError] = useState('');
  const [offer, setOffer] = useState('');
  const [price, setPrice] = useState('');
  const [busy, setBusy] = useState(false);

  useEffect(() => {
    const queryHandle = normalizedQueryHandle(routeHandleQuery(route));
    if (!queryHandle) return undefined;
    setHandle(queryHandle);
    let cancelled = false;
    setBusy(true); setError('');
    searchPortalHandleMarketplace(queryHandle).then((record) => {
      if (!cancelled) { setResult(record); setStep('detail'); }
    }).catch((reason) => !cancelled && setError(firebaseMessage(reason))).finally(() => !cancelled && setBusy(false));
    return () => { cancelled = true; };
  }, [route]);

  async function search(event) {
    event.preventDefault();
    const next = normalizedQueryHandle(handle);
    if (!next) return;
    setBusy(true); setError(''); setPaymentNotice(''); setPurchase(null);
    try {
      const record = await searchPortalHandleMarketplace(next);
      setResult(record); setStep('detail'); window.location.hash = `#/marketplace?handle=${next}`;
    } catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); }
  }
  async function list() {
    setBusy(true); setError('');
    try { await createPortalHandleListing(result.handle.normalizedHandle, Number(price)); setResult(await searchPortalHandleMarketplace(result.handle.normalizedHandle)); }
    catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); }
  }
  async function makeOffer() { setBusy(true); setError(''); try { await submitPortalHandleOffer(result.listing.listingId, Number(offer)); setOffer(''); } catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); } }
  async function dispute() { setBusy(true); setError(''); try { await openPortalHandleDispute(result.listing.listingId); setResult(await searchPortalHandleMarketplace(result.handle.normalizedHandle)); } catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); } }
  async function startPurchase() {
    setBusy(true); setError('');
    try { setPurchase(await startPortalHandlePurchase(result.details.normalizedHandle)); setStep('review'); }
    catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); }
  }
  async function confirmPurchase() {
    setBusy(true); setError('');
    try { const confirmation = await confirmPortalHandlePurchase(purchase.purchaseId); setPaymentNotice(confirmation.message || 'Placeholder payment approved.'); setPurchase({ ...purchase, ...confirmation }); setStep('confirmation'); }
    catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); }
  }
  async function completePurchase() {
    setBusy(true); setError('');
    try { setPurchase({ ...purchase, ...(await completePortalHandlePurchase(purchase.purchaseId)) }); setStep('success'); }
    catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); }
  }

  const listing = result?.listing;
  const details = result?.details;
  const pricing = result?.pricing || {};
  const state = result?.state || details?.availability || 'Unavailable';
  const canPurchase = result && ['Available', 'Premium'].includes(state) && pricing.amountMinor != null && !listing;
  const isOwner = result?.handle?.ownerUid === user.uid || result?.handle?.uid === user.uid;
  const purchaseLabel = pricing.amountMinor == null ? 'Request pricing' : state === 'Premium' ? 'Review premium purchase' : 'Reserve';

  return <div className="page marketplace-page"><div><h1 className="display-xl">Handle Marketplace</h1><p className="body-md">Reserve, discover and trade eligible Portal identities.</p></div><form className="glass card form-stack handle-search-card" onSubmit={search}><label>Search handles<div className="handle-input"><span aria-hidden="true">@</span><input value={handle} onChange={(event) => setHandle(event.target.value.replace(/^@/, ''))} placeholder="Search a Portal handle" autoCapitalize="none" autoCorrect="off" /></div></label><button className="btn btn-primary" disabled={busy || !handle.trim()}>{busy ? 'Searching...' : 'Search'}</button></form>{error ? <p className="form-error" role="alert">{error}</p> : null}{step === 'search' && !result ? <div className="glass card empty-state"><h2 className="display-md">Find a Portal identity</h2><p className="body-sm">Search any handle to see availability, pricing, protection and marketplace status.</p></div> : null}{result && step === 'detail' ? <section className="glass card marketplace-card handle-detail-card"><div className="handle-detail-head"><div><span className={`state-badge state-${state.toLowerCase().replaceAll(' ', '-')}`}>{state}</span><h2 className="display-lg">@{details.normalizedHandle}</h2><p className="body-sm">{state === 'Protected' ? 'This handle is protected and is not available for sale.' : details.description}</p></div><div className="price-lockup"><span className="eyebrow">Price</span><strong>{formatMoney(pricing.amountMinor, pricing.currency)}</strong><span className="body-sm">{pricing.periodMonths ? `${pricing.periodMonths} month registration` : 'Marketplace terms'}</span></div></div><div className="handle-detail-grid"><div><span className="eyebrow">Availability</span><strong>{details.availability}</strong></div><div><span className="eyebrow">Category</span><strong>{details.category}</strong></div><div><span className="eyebrow">Registration period</span><strong>{details.registrationPeriodMonths ? `${details.registrationPeriodMonths} months` : 'Not available'}</strong></div><div><span className="eyebrow">Renewal price</span><strong>{formatMoney(details.renewalPriceMinor, details.currency)}</strong></div><div><span className="eyebrow">Transfer eligibility</span><strong>{details.transferEligibility}</strong></div><div><span className="eyebrow">Verification required</span><strong>{details.verificationRequired ? 'Yes' : 'No'}</strong></div></div>{details.developmentPaymentMode ? <div className="dev-payment-banner"><strong>Development Payment Mode</strong><span>No real payment has been taken.</span></div> : null}{state === 'Reserved' ? <p className="form-error">This handle is reserved and cannot be claimed.</p> : null}{state === 'Protected' ? <p className="form-error">This handle is protected and is not available for sale.</p> : null}{state === 'Coming Soon' ? <p className="form-notice">This handle category is coming soon.</p> : null}{state === 'Owned' && !listing ? <p className="form-notice">{isOwner ? 'Your current Portal identity.' : 'This handle is owned. Owner details are hidden unless it is listed for sale.'}</p> : null}{listing ? <div className="listing-panel"><div className="metrics"><span>{listing.listingStatus}</span><span>{formatMoney(listing.askingPriceAmount, listing.currency)}</span><span>{listing.ownershipType}</span></div>{listing.ownershipType === 'user_owned' ? <p className="form-notice">Portal-managed checkout is being prepared. This handle cannot be transferred outside Portal.</p> : null}{listing.sellerUid !== user.uid && listing.listingStatus === 'active' ? <div className="form-actions"><input className="market-input" type="number" placeholder="Offer (minor units)" value={offer} onChange={(event) => setOffer(event.target.value)} /><button className="btn btn-secondary" type="button" disabled={busy || !offer} onClick={makeOffer}>Make offer</button></div> : null}{listing.sellerUid === user.uid && !listing.disputeState ? <button className="btn btn-secondary btn-sm" type="button" disabled={busy} onClick={dispute}>Open dispute</button> : null}</div> : null}{!listing && isOwner ? <div className="form-stack"><label>Seller listing price (minor units)<input type="number" value={price} onChange={(event) => setPrice(event.target.value)} /></label><button className="btn btn-secondary" type="button" disabled={busy || !price} onClick={list}>Create marketplace listing</button></div> : null}<div className="form-actions"><button className="btn btn-primary" type="button" disabled={busy || !canPurchase} onClick={startPurchase}>{purchaseLabel}</button><a className="btn btn-secondary" href="#/profile">View Profile handles</a></div></section> : null}{purchase && step === 'review' ? <section className="glass card marketplace-card"><span className="step-pill">Reserve → Review → Payment → Confirmation</span><h2 className="display-lg">Review @{result.details.normalizedHandle}</h2><div className="receipt-grid"><span>Handle</span><strong>@{result.details.normalizedHandle}</strong><span>Price</span><strong>{formatMoney(pricing.amountMinor, pricing.currency)}</strong><span>Renewal</span><strong>{formatMoney(pricing.renewalAmountMinor, pricing.currency)} / year</strong><span>Terms</span><strong>{pricing.periodMonths} month registration</strong><span>Refund policy</span><strong>Development purchases can be refunded by Portal admin.</strong></div><div className="form-actions"><button className="btn btn-primary" type="button" disabled={busy} onClick={() => setStep('payment')}>Continue</button><button className="btn btn-secondary" type="button" disabled={busy} onClick={() => setStep('detail')}>Cancel</button></div></section> : null}{purchase && step === 'payment' ? <section className="glass card marketplace-card payment-card"><div className="dev-payment-banner"><strong>Development Payment Mode</strong><span>No real payment has been taken.</span></div><h2 className="display-lg">Payment Provider</h2><p className="body-md">(Temporary Development Mode)</p><div className="payment-method-grid">{['Credit Card', 'Apple Pay', 'Google Pay', 'PayPal'].map((method) => <div className="glass card compact-empty payment-method" key={method}><strong>{method}</strong><span className="source-chip">Coming Soon</span></div>)}</div><button className="btn btn-primary" type="button" disabled={busy} onClick={confirmPurchase}>{busy ? 'Approving...' : 'Development Purchase'}</button><button className="btn btn-secondary" type="button" disabled={busy} onClick={() => setStep('review')}>Cancel payment</button></section> : null}{purchase && step === 'confirmation' ? <section className="glass card marketplace-card"><h2 className="display-lg">Placeholder payment approved.</h2><p className="body-sm">{paymentNotice}</p><div className="receipt-grid"><span>Purchase reference</span><strong>{purchase.purchaseId}</strong><span>Temporary payment token</span><strong>{purchase.temporaryPaymentToken ? 'Generated' : 'Pending'}</strong></div><button className="btn btn-primary" type="button" disabled={busy} onClick={completePurchase}>{busy ? 'Assigning...' : 'Complete purchase and assign handle'}</button></section> : null}{purchase && step === 'success' ? <section className="glass card marketplace-card success-card"><h2 className="display-lg">✓ Handle Reserved</h2><p className="profile-handle">@{purchase.handle || result.details.normalizedHandle}</p><div className="receipt-grid"><span>Purchase reference</span><strong>{purchase.purchaseId}</strong><span>Renewal date</span><strong>{purchase.renewalDate?.toDate ? purchase.renewalDate.toDate().toLocaleDateString() : 'One year from today'}</strong><span>Registration period</span><strong>{purchase.registrationPeriodMonths || pricing.periodMonths} months</strong></div><div className="form-actions"><a className="btn btn-primary" href="#/profile">Go to profile</a><a className="btn btn-secondary" href="#/">Go to Portal</a><a className="btn btn-secondary" href={`/@${purchase.handle || result.details.normalizedHandle}`}>Share profile</a></div></section> : null}</div>;
}

function AdminHandleRegistry() {
  const [term, setTerm] = useState(''); const [record, setRecord] = useState(null); const [error, setError] = useState(''); const [busy, setBusy] = useState(false); const [action, setAction] = useState('protect'); const [category, setCategory] = useState('brand'); const [notes, setNotes] = useState(''); const [reclaimOpen, setReclaimOpen] = useState(false); const [reason, setReason] = useState('impersonation'); const [outcome, setOutcome] = useState('mark_protected'); const [claimantUid, setClaimantUid] = useState(''); const [confirmation, setConfirmation] = useState(''); const [highRiskConfirmed, setHighRiskConfirmed] = useState(false);
  async function search(event) { event.preventDefault(); setBusy(true); setError(''); try { setRecord(await getPortalAdminHandle(term)); } catch (err) { setError(firebaseMessage(err)); } finally { setBusy(false); } }
  async function manage(event) { event.preventDefault(); setBusy(true); setError(''); try { await managePortalHandleRegistry({ handle: record.normalizedHandle, action, category, notes, ...(action === 'verify_owner' ? { verifiedUid: claimantUid } : {}) }); setRecord(await getPortalAdminHandle(record.normalizedHandle)); } catch (err) { setError(firebaseMessage(err)); } finally { setBusy(false); } }
  async function reclaim(event) { event.preventDefault(); setBusy(true); setError(''); try { await reclaimPortalHandle({ handle: record.normalizedHandle, reason, notes, outcome, claimantUid: claimantUid || null, confirmation, highRiskConfirmed }); setReclaimOpen(false); setRecord(await getPortalAdminHandle(record.normalizedHandle)); } catch (err) { setError(firebaseMessage(err)); } finally { setBusy(false); } }
  async function refundPurchase(purchaseId) { setBusy(true); setError(''); try { await refundPlaceholderPortalHandlePurchase(purchaseId); setRecord(await getPortalAdminHandle(record.normalizedHandle)); } catch (err) { setError(firebaseMessage(err)); } finally { setBusy(false); } }
  return <div className="page"><div><h1 className="display-xl">Handle management</h1><p className="body-md">Protected Handle Registry controls. Every action is recorded.</p></div><form className="glass card form-stack" onSubmit={search}><label>Search handle<input value={term} onChange={(event) => setTerm(event.target.value.replace(/^@/, ''))} placeholder="@handle" /></label><button className="btn btn-primary" disabled={busy}>Search registry</button></form>{error ? <p className="form-error" role="alert">{error}</p> : null}{record ? <><section className="glass card marketplace-card"><div><h2 className="display-lg">@{record.normalizedHandle}</h2><p className="body-sm">{record.protected?.status || record.reserved?.status || record.policy?.status || record.handle?.status || 'available'}</p></div><div className="metrics"><span>{record.protected?.category || record.reserved?.category || record.policy?.category || record.handle?.marketplaceClass || 'unclassified'}</span><span>{record.handle?.ownerUid ? 'Owned' : 'No active owner'}</span></div></section><section className="glass card"><h2 className="display-md">Identity risk review</h2>{record.requests?.length ? <div className="stack">{record.requests.map((item) => <article className="glass card compact-empty" key={item.id || item.requestId}><div className="inline-meta"><span className="source-chip">{item.requestType}</span><span className="source-chip">{item.status}</span><span className="source-chip">{item.riskBand}</span></div><p className="body-sm">Risk score {item.riskScore} · Email {item.emailVerified ? 'verified' : 'not verified'} · Phone {item.phoneVerified ? 'verified' : 'not verified'}</p><p className="body-sm">Device matches {item.deviceMatchCount || 0} · Browser matches {item.browserMatchCount || 0}</p><p className="body-sm">{(item.riskReasons || []).map((reason) => reason.code).join(', ') || 'No risk reasons recorded.'}</p></article>)}</div> : <p className="body-sm">No handle risk reviews recorded for this handle.</p>}</section><section className="glass card"><h2 className="display-md">Handle purchases</h2>{record.purchases?.length ? <div className="stack">{record.purchases.map((item) => <article className="glass card compact-empty" key={item.id || item.purchaseId}><div className="inline-meta"><span className="source-chip">{item.paymentProviderMode || item.provider || 'unknown provider'}</span><span className="source-chip">{item.paymentStatus || item.status}</span><span className="source-chip">{item.issuanceState || 'not issued'}</span></div><p className="body-sm">{formatMoney(item.amountMinor, item.currency)} · Buyer {item.uid} · Renewal {timeLabel(item.renewalDate)}</p><p className="body-sm">Placeholder purchases can be converted later when the permanent provider is active.</p>{item.paymentProviderMode === 'placeholder' && item.paymentStatus !== 'refunded' ? <button className="btn btn-secondary btn-sm" type="button" disabled={busy} onClick={() => refundPurchase(item.purchaseId || item.id)}>Refund placeholder purchase</button> : null}</article>)}</div> : <p className="body-sm">No purchases recorded for this handle.</p>}</section><section className="glass card"><h2 className="display-md">Registry action</h2><form className="form-stack" onSubmit={manage}><label>Action<select value={action} onChange={(event) => setAction(event.target.value)}>{['protect', 'reserve', 'marketplace', 'release', 'retire', 'verify_owner'].map((item) => <option key={item} value={item}>{item.replaceAll('_', ' ')}</option>)}</select></label><label>Category<input value={category} onChange={(event) => setCategory(event.target.value)} /></label>{action === 'verify_owner' ? <label>Verified owner UID<input value={claimantUid} onChange={(event) => setClaimantUid(event.target.value)} /></label> : null}<label>Internal notes<textarea value={notes} onChange={(event) => setNotes(event.target.value)} /></label><button className="btn btn-secondary" disabled={busy}>Apply registry action</button></form></section><section className="glass card"><h2 className="display-md">Enforcement</h2><p className="body-sm">Reclaim Handle requires a reason, internal notes and typed confirmation. It is never a one-click action.</p><button className="btn btn-primary" type="button" onClick={() => setReclaimOpen(true)}>Reclaim Handle</button></section>{reclaimOpen ? <section className="glass card"><h2 className="display-md">Reclaim @{record.normalizedHandle}</h2><form className="form-stack" onSubmit={reclaim}><label>Reason<select value={reason} onChange={(event) => setReason(event.target.value)}>{['impersonation', 'trademark', 'fraud', 'abuse', 'legal_compliance', 'public_interest', 'system_use', 'enforcement'].map((item) => <option key={item}>{item.replaceAll('_', ' ')}</option>)}</select></label><label>Outcome<select value={outcome} onChange={(event) => setOutcome(event.target.value)}>{['mark_protected', 'permanently_reserve', 'assign_verified_claimant', 'assign_portal_account', 'return_to_marketplace', 'release_to_availability'].map((item) => <option key={item}>{item.replaceAll('_', ' ')}</option>)}</select></label>{outcome.includes('assign_') ? <label>Receiving Portal UID<input value={claimantUid} onChange={(event) => setClaimantUid(event.target.value)} /></label> : null}<label>Internal notes<textarea value={notes} onChange={(event) => setNotes(event.target.value)} required minLength="8" /></label><label>Type RECLAIM @{record.normalizedHandle}<input value={confirmation} onChange={(event) => setConfirmation(event.target.value)} /></label><label className="check-row"><input type="checkbox" checked={highRiskConfirmed} onChange={(event) => setHighRiskConfirmed(event.target.checked)} /> I confirm this may be a high-risk reclaim.</label><div className="form-actions"><button className="btn btn-primary" disabled={busy}>Confirm reclaim</button><button className="btn btn-secondary" type="button" onClick={() => setReclaimOpen(false)}>Cancel</button></div></form></section> : null}</> : null}</div>;
}

function AdminWorkspace({ current }) {
  const handles = current === '/admin/handles';
  return <main className="admin-shell"><header className="admin-topbar"><Brand /><div><span className="eyebrow">Staff only</span><strong>Portal administration</strong></div><a className="btn btn-secondary btn-sm" href="#/profile">Return to Portal</a></header><div className="admin-layout"><nav className="admin-nav" aria-label="Portal administration"><a href="#/admin" aria-current={!handles ? 'page' : undefined}>Overview</a><a href="#/admin/handles" aria-current={handles ? 'page' : undefined}>Handle Registry</a></nav><section className="admin-content">{handles ? <AdminHandleRegistry /> : <div className="page"><div><h1 className="display-xl">Portal administration</h1><p className="body-md">Controlled operational surfaces for Portal staff.</p></div><section className="glass card"><h2 className="display-md">Handle Registry</h2><p className="body-sm">Search, classify and reclaim protected Portal identities. Access is checked by server-authoritative custom claims.</p><a className="btn btn-primary" href="#/admin/handles">Open Handle Registry</a></section></div>}</section></div></main>;
}

function HandleIdentity({ profile }) {
  const [handle, setHandle] = useState(profile?.handle || ''); const [state, setState] = useState(''); const [notice, setNotice] = useState(''); const [busy, setBusy] = useState(false);
  useEffect(() => { setHandle(profile?.handle || ''); }, [profile?.handle]);
  useEffect(() => { const next = handle.trim(); if (!next || next.length < 3 || next === profile?.handle) { setState(''); return undefined; } setState('Checking'); const timer = window.setTimeout(async () => { try { const result = await checkPortalHandle(next); setState(result.available ? 'Available' : ({ taken: 'Already taken', reserved: 'Reserved', protected: 'Protected', invalid: 'Invalid' }[result.state] || 'Already taken')); } catch { setState('Temporarily unavailable'); } }, 350); return () => window.clearTimeout(timer); }, [handle, profile?.handle]);
  async function reserve(event) { event.preventDefault(); if (!handle.trim() || busy) return; setBusy(true); setNotice(''); try { const result = profile?.normalizedHandle ? await changePortalHandle(handle) : await reservePortalHandle(handle); setNotice(`@${result.handle} is yours.`); setState('Reserved'); } catch (reason) { setNotice(firebaseMessage(reason)); } finally { setBusy(false); } }
  return <section className="glass card"><h2 className="display-md">Portal identity</h2><p className="body-sm">This is how people will recognise, mention and find you across Portal.</p><form className="form-stack" onSubmit={reserve}><label>Handle<div className="handle-input"><span aria-hidden="true">@</span><input value={handle} onChange={(event) => setHandle(event.target.value.replace(/^@/, ''))} minLength="3" maxLength="24" autoCapitalize="none" autoCorrect="off" /></div></label>{state ? <p className={state === 'Available' || state === 'Reserved' ? 'form-notice' : 'form-error'} role="status">{state}</p> : null}{notice ? <p className="form-notice" role="status">{notice}</p> : null}<button className="btn btn-primary" disabled={busy || state === 'Already taken' || state === 'Reserved' || state === 'Protected' || state === 'Invalid' || state === 'Checking'}>{busy ? 'Reserving...' : profile?.normalizedHandle ? 'Change handle' : 'Reserve handle'}</button></form></section>;
}

function ProfileSetup({ user, profile }) {
  const [values, setValues] = useState({ displayName: profile?.displayName || user.displayName || '', handle: '', bio: profile?.bio || '', location: profile?.location || '', website: profile?.website || '' });
  const [photo, setPhoto] = useState(null); const [availability, setAvailability] = useState(''); const [message, setMessage] = useState(''); const [error, setError] = useState(''); const [busy, setBusy] = useState(false); const [progress, setProgress] = useState(0);
  useEffect(() => { const handle = values.handle.trim(); if (!handle) { setAvailability(''); return undefined; } setAvailability('Checking'); const timer = window.setTimeout(async () => { try { const result = await checkPortalHandle(handle); setAvailability(result.available ? 'Available' : ({ taken: 'Already taken', reserved: 'Reserved', protected: 'Protected', invalid: 'Invalid' }[result.state] || 'Already taken')); } catch { setAvailability('Temporarily unavailable'); } }, 400); return () => window.clearTimeout(timer); }, [values.handle]);
  function update(field, value) { setValues((current) => ({ ...current, [field]: value })); }
  function selectPhoto(file) { if (!file) { setPhoto(null); return; } if (!file.type.startsWith('image/') || file.size > 10 * 1024 * 1024) { setError('Choose an image file up to 10 MB.'); return; } setError(''); setPhoto(file); }
  async function createProfile(event) {
    event.preventDefault(); if (busy) return;
    if (!values.displayName.trim()) { setError('Display name is required.'); return; }
    if (!values.handle.trim()) { setAvailability('Invalid'); setError('Choose your unique handle before creating your profile.'); return; }
    if (['Checking', 'Already taken', 'Reserved', 'Protected', 'Invalid', 'Temporarily unavailable'].includes(availability)) return;
    setBusy(true); setError(''); setMessage('');
    try {
      await reservePortalHandle(values.handle, { displayName: values.displayName.trim(), bio: values.bio.trim(), location: values.location.trim(), website: values.website.trim() });
      if (photo) { const profilePhotoUrl = await uploadPortalProfilePhoto(user, photo, setProgress); await updatePortalProfile(user, { profilePhotoUrl }); }
      setMessage('Profile created. Welcome properly to Portal.');
      window.location.hash = '#/settings';
    } catch (reason) {
      if (reason?.code === 'already-exists') { setAvailability('Already taken'); setError('That handle was just taken. Please choose another.'); } else setError(firebaseMessage(reason));
    } finally { setBusy(false); }
  }
  const blocked = busy || !values.handle.trim() || !values.displayName.trim() || availability !== 'Available';
  return <div className="page profile-setup"><div><h1 className="display-xl">Create your Profile</h1><p className="body-md">Choose how Portal remembers and introduces you.</p></div><section className="glass card"><form className="form-stack" onSubmit={createProfile}><label>Profile photo <input type="file" accept="image/*" onChange={(event) => selectPhoto(event.target.files?.[0])} /></label>{photo ? <p className="body-sm">{photo.name}{progress ? ` · Upload ${progress}%` : ''}</p> : null}<label>Display name<input value={values.displayName} onChange={(event) => update('displayName', event.target.value)} required maxLength="80" /></label><label>Handle<div className="handle-input"><span aria-hidden="true">@</span><input value={values.handle} onChange={(event) => update('handle', event.target.value.replace(/^@/, ''))} placeholder={PROFILE_HANDLE_PLACEHOLDER} required minLength="3" maxLength="24" autoCapitalize="none" autoCorrect="off" /></div></label>{availability ? <p className={availability === 'Available' ? 'form-notice' : availability === 'Checking' ? 'form-status' : 'form-error'} role="status">{availability}</p> : null}<label>Bio <textarea value={values.bio} onChange={(event) => update('bio', event.target.value)} maxLength="240" /></label><label>Location <input value={values.location} onChange={(event) => update('location', event.target.value)} maxLength="120" /></label><label>Website <input value={values.website} onChange={(event) => update('website', event.target.value)} type="url" placeholder="https://" maxLength="200" /></label>{error ? <p className="form-error" role="alert">{error}</p> : null}{message ? <p className="form-notice" role="status">{message}</p> : null}<div className="form-actions"><button className="btn btn-primary" disabled={blocked}>{busy ? 'Creating profile...' : 'Create Profile'}</button><button className="btn btn-secondary" type="button" disabled={blocked} onClick={createProfile}>Reserve Handle</button></div></form></section></div>;
}

function PersonalProfile({ user, profile, posts, echoActivity, handlePurchases, echoedPostIds, onEcho, onQuote }) {
  const displayName = profile?.displayName || user.displayName || 'Portal member';
  const handle = profile?.handle || '';
  const [tab, setTab] = useState('Posts'); const activityPosts = tab === 'Echoes' ? echoActivity.map((echo) => { const post = posts.find((item) => item.id === echo.sourcePostId); return post ? { ...post, echoedByHandle: handle } : null; }).filter(Boolean) : tab === 'Media' ? posts.filter((post) => post.media) : tab === 'Replies' ? [] : posts.filter((post) => post.authorUid === user.uid || post.createdBy === user.uid);
  const issuedPurchases = handlePurchases.filter((item) => item.status === 'assigned' || item.issuanceState === 'issued');
  const pendingPurchases = handlePurchases.filter((item) => ['review', 'payment_approved', 'pending_review'].includes(item.status) || ['not_issued', 'pending_review'].includes(item.issuanceState));
  return <div className="page personal-profile"><div className="profile-cover" aria-hidden="true" /><section className="glass card personal-profile-card"><Avatar size="lg">{initials(displayName)}</Avatar><div className="personal-profile-main"><div><h1 className="display-xl">{displayName}</h1><p className="profile-handle">@{handle}</p></div><div className="form-actions"><a className="btn btn-primary btn-sm" href="#/settings">Edit profile</a><a className="btn btn-secondary btn-sm" href={`/@${handle}`}>View public profile</a></div></div>{profile?.bio ? <p className="body-md">{profile.bio}</p> : <p className="body-sm">Add a bio so people know which corner of humanity&apos;s memory you&apos;re building.</p>}<div className="profile-details">{profile?.location ? <span>{profile.location}</span> : null}{profile?.website ? <a href={profile.website} target="_blank" rel="noreferrer">{profile.website.replace(/^https?:\/\//, '')}</a> : null}<span>Joined {timeLabel(profile?.createdAt)}</span></div></section><Section title="Handles"><div className="profile-option-list handles-summary">{profile?.normalizedHandle ? <a className="glass card interactive profile-option-row" href={`#/marketplace?handle=${profile.normalizedHandle}`}><span><strong>@{profile.normalizedHandle}</strong><span className="body-sm">Active free handle · {profile.verificationState || 'unverified'}</span></span><span className="source-chip">Free</span></a> : null}{issuedPurchases.map((item) => <a className="glass card interactive profile-option-row" href={`#/marketplace?handle=${item.normalizedHandle}`} key={item.purchaseId || item.id}><span><strong>@{item.normalizedHandle}</strong><span className="body-sm">{item.status === 'rescinded' ? 'Rescinded' : 'Issued'} · Renewal {timeLabel(item.renewalDate)}</span></span><span className="source-chip">{item.handleType || 'Paid'}</span></a>)}{pendingPurchases.map((item) => <a className="glass card interactive profile-option-row" href={`#/marketplace?handle=${item.normalizedHandle}`} key={item.purchaseId || item.id}><span><strong>@{item.normalizedHandle}</strong><span className="body-sm">Pending review or assignment · {item.paymentStatus || item.status}</span></span><span className="source-chip">Pending</span></a>)}{!profile?.normalizedHandle && !issuedPurchases.length && !pendingPurchases.length ? <div className="glass card compact-empty"><p className="body-sm">No handles are currently associated with this account.</p><a className="btn btn-primary btn-sm" href="#/marketplace">Open Handle Marketplace</a></div> : null}</div></Section><Section title="Your activity"><div className="profile-tabs">{['Posts', 'Replies', 'Echoes', 'Media'].map((item) => <button className={`profile-tab ${tab === item ? 'active' : ''}`} type="button" onClick={() => setTab(item)} key={item}>{item}</button>)}</div><div className="stack">{activityPosts.length ? activityPosts.map((post) => <PostCard key={`${tab}-${post.id}`} post={post} echoed={echoedPostIds.has(post.id)} onEcho={onEcho} onQuote={onQuote} />) : <div className="glass card compact-empty"><p className="body-sm">No {tab.toLowerCase()} here yet.</p></div>}</div></Section><Section title="Account and profile options"><div className="profile-option-list"><a className="glass card interactive profile-option-row" href="#/settings"><span><strong>Settings</strong><span className="body-sm">Identity, preferences, password and safety.</span></span><span className="see-all">Open</span></a><a className="glass card interactive profile-option-row" href="#/memory"><span><strong>Portal+ Memory</strong><span className="body-sm">Private memory tools will live here as Portal+ expands.</span></span><span className="source-chip">Limited</span></a><a className="glass card interactive profile-option-row" href="#/contributors"><span><strong>Contributor Hub</strong><span className="body-sm">Creator tools, reporting activity and contributor context.</span></span><span className="source-chip">Limited</span></a></div></Section></div>;
}

function FeaturePage({ title, description, children }) {
  return <div className="page"><div><h1 className="display-xl">{title}</h1><p className="body-md">{description}</p></div>{children || <div className="glass card empty-state compact-empty"><h2 className="display-md">Limited for now</h2><p className="body-sm">This destination is available from Profile while Portal keeps Home, Events and Vortex in front.</p></div>}</div>;
}

function notificationText(item) {
  const handle = item.authorHandle ? `@${item.authorHandle.replace(/^@/, '')}` : 'Someone';
  if (item.type === 'quote_echo') return `${handle} added a Quote Echo to your Post.`;
  if (item.type === 'echo') return `${handle} echoed your Post.`;
  if (item.type === 'event_update') return item.summary || 'An Event you follow changed meaningfully.';
  if (item.type === 'handle_reclaim') return 'A handle action needs your attention.';
  return 'Portal has an update for you.';
}

function Notifications({ user }) {
  const [items, setItems] = useState([]); const [loading, setLoading] = useState(true); const [error, setError] = useState('');
  useEffect(() => { const stop = observePortalNotifications(user.uid, (snapshot) => { setItems(snapshot.docs.map((item) => ({ id: item.id, ...item.data() }))); setLoading(false); }, (reason) => { setError(firebaseMessage(reason)); setLoading(false); }); return stop; }, [user.uid]);
  async function open(item) { if (!item.read) { try { await markPortalNotificationRead(user.uid, item.id); } catch { /* read status can recover on the next refresh */ } } if (item.eventId) window.location.hash = `#/events/${item.eventId}`; else if (item.postId) window.location.hash = `#/posts/${item.postId}`; }
  if (loading) return <Loading label="Gathering notifications..." />;
  if (error) return <ErrorState message={error} />;
  return <div className="page"><div><h1 className="display-xl">Notifications</h1><p className="body-md">Echoes, Quote Echoes and important Portal activity.</p></div><div className="stack">{items.length ? items.map((item) => <button key={item.id} className={`glass card notification-card ${item.read ? '' : 'unread'}`} type="button" onClick={() => open(item)}><span>{notificationText(item)}</span><small>{timeLabel(item.createdAt)}</small></button>) : <div className="glass card empty-state compact-empty"><h2 className="display-md">Quiet for now</h2><p className="body-sm">When someone Echoes or Quote Echoes your Post, it will land here.</p></div>}</div></div>;
}

function Custodians() {
  const [providers, setProviders] = useState([]); const [loading, setLoading] = useState(true); const [error, setError] = useState('');
  useEffect(() => { const stop = observeIngestionProviders((snapshot) => { setProviders(snapshot.docs.map((item) => ({ id: item.id, ...item.data() }))); setLoading(false); }, (reason) => { setError(firebaseMessage(reason)); setLoading(false); }); return stop; }, []);
  return <div className="page"><div><h1 className="display-xl">Custodians</h1><p className="body-md">Review queues for duplicate Events, disputed facts, misleading media, protected identity concerns and corrections.</p></div><section className="glass card"><h2 className="display-md">Custodian queues</h2><p className="body-sm">Suspected duplicates and disputes are created server-side and audited. Staff tooling opens from Portal administration.</p><a className="btn btn-primary" href="#/admin">Open admin</a></section><Section title="Provider health">{loading ? <Loading label="Checking provider health..." /> : error ? <div className="glass card compact-empty"><p className="body-sm">Provider health is visible only to authorised Custodians.</p></div> : providers.length ? <div className="stack">{providers.map((provider) => <article className="glass card provider-health-card" key={provider.id}><div className="inline-meta"><span className="source-chip">{provider.enabled ? 'Enabled' : 'Disabled'}</span><span className="source-chip">{provider.rolloutStage || 'shadow'}</span><span className="source-chip">{provider.healthState || 'unknown'}</span></div><strong>{provider.displayName || provider.id}</strong><p className="body-sm">{provider.category} · Last success {timeLabel(provider.lastSuccessfulRunAt)} · Last failure {provider.lastError || 'none'}</p><div className="metrics"><span>{provider.lastCandidateCount || 0} candidates</span><span>{provider.lastCreatedCount || 0} created</span><span>{provider.lastAttachedCount || 0} attached</span><span>{provider.lastReviewCount || 0} reviews</span></div></article>)}</div> : <div className="glass card empty-state compact-empty"><p className="body-sm">No providers configured yet.</p></div>}</Section></div>;
}

function Settings({ user, profile }) {
  const [displayName, setDisplayName] = useState(profile?.displayName || user.displayName || ''); const [emailUpdates, setEmailUpdates] = useState(profile?.preferences?.emailUpdates ?? true); const [password, setPassword] = useState(''); const [notice, setNotice] = useState(''); const [error, setError] = useState(''); const [busy, setBusy] = useState(false);
  useEffect(() => { setDisplayName(profile?.displayName || user.displayName || ''); setEmailUpdates(profile?.preferences?.emailUpdates ?? true); }, [profile, user.displayName]);
  async function save(event) { event.preventDefault(); setBusy(true); setError(''); try { await updatePortalProfile(user, { displayName: displayName.trim(), emailUpdates }); setNotice('Profile saved.'); } catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); } }
  async function passwordChange(event) { event.preventDefault(); if (password.length < 8) { setError('Use at least 8 characters for a new password.'); return; } setBusy(true); setError(''); try { await changePortalPassword(password); setPassword(''); setNotice('Password updated.'); } catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); } }
  return <div className="page"><div><h1 className="display-xl">Settings</h1><p className="body-md">Your Portal profile and private preferences.</p></div>{notice ? <p className="form-notice" role="status">{notice}</p> : null}{error ? <p className="form-error" role="alert">{error}</p> : null}<HandleIdentity profile={profile} /><section className="glass card"><h2 className="display-md">Profile</h2><form className="form-stack" onSubmit={save}><label>Name<input value={displayName} onChange={(event) => setDisplayName(event.target.value)} required maxLength="80" /></label><label>Email<input value={user.email || ''} disabled /></label><label className="check-row"><input type="checkbox" checked={emailUpdates} onChange={(event) => setEmailUpdates(event.target.checked)} /> Email updates</label><button className="btn btn-primary" disabled={busy}>Save preferences</button></form></section><section className="glass card"><h2 className="display-md">Security</h2><form className="form-stack" onSubmit={passwordChange}><label>New password<input type="password" value={password} onChange={(event) => setPassword(event.target.value)} minLength="8" /></label><button className="btn btn-secondary" disabled={busy}>Update password</button></form></section><button className="btn btn-secondary" type="button" onClick={() => signOutPortalUser()}>Sign out</button></div>;
}

function AuthScreen() {
  const [mode, setMode] = useState('signin'); const [values, setValues] = useState({ name: '', email: '', password: '' }); const [busy, setBusy] = useState(false); const [error, setError] = useState(''); const [notice, setNotice] = useState('');
  async function submit(event) { event.preventDefault(); setBusy(true); setError(''); setNotice(''); try { if (mode === 'signup') { if (values.name.trim().length < 2) throw new Error('Please add your name.'); await registerPortalUser({ displayName: values.name.trim(), email: values.email.trim(), password: values.password }); } else if (mode === 'reset') { await sendPortalPasswordReset(values.email.trim()); setNotice('A password reset email has been sent.'); } else { await signInPortalUser(values.email.trim(), values.password); } } catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); } }
  return <main className="auth-shell"><div className="auth-panel"><Brand /><div><h1 className="display-xl">{mode === 'signup' ? 'Create your Portal' : mode === 'reset' ? 'Reset your password' : 'Welcome back'}</h1><p className="body-md">{mode === 'signup' ? 'Start organising the world’s happenings.' : 'Enter Portal’s living memory.'}</p></div>{!hasFirebaseConfig ? <ErrorState message="Firebase environment configuration is missing." /> : <form className="form-stack" onSubmit={submit}>{mode === 'signup' ? <label>Name<input value={values.name} onChange={(event) => setValues({ ...values, name: event.target.value })} required /></label> : null}<label>Email<input type="email" value={values.email} onChange={(event) => setValues({ ...values, email: event.target.value })} required autoComplete="email" /></label>{mode !== 'reset' ? <label>Password<input type="password" value={values.password} onChange={(event) => setValues({ ...values, password: event.target.value })} required minLength="8" autoComplete={mode === 'signup' ? 'new-password' : 'current-password'} /></label> : null}{error ? <p className="form-error" role="alert">{error}</p> : null}{notice ? <p className="form-notice" role="status">{notice}</p> : null}<button className="btn btn-primary" disabled={busy}>{busy ? 'Please wait...' : mode === 'signup' ? 'Create account' : mode === 'reset' ? 'Send reset email' : 'Sign in'}</button></form>}<div className="auth-links">{mode !== 'signin' ? <button type="button" onClick={() => setMode('signin')}>Sign in</button> : <button type="button" onClick={() => setMode('signup')}>Create an account</button>}{mode === 'signin' ? <button type="button" onClick={() => setMode('reset')}>Forgot password?</button> : null}</div></div></main>;
}

function CreateModal({ open, onClose, user, profile, events }) {
  const [busy, setBusy] = useState(false); const [error, setError] = useState(''); const [progress, setProgress] = useState({});
  const [values, setValues] = useState({ title: '', description: '', location: '', occurredAt: '', identityMode: 'Reporter', eventId: '', eventTitle: '', photo: null, video: null });
  if (!open) return null;
  if (!profile?.normalizedHandle) return <div className="modal-overlay" role="dialog" aria-modal="true" aria-labelledby="identityRequiredTitle" onMouseDown={onClose}><div className="modal form-modal" onMouseDown={(event) => event.stopPropagation()}><div className="modal-head"><h2 id="identityRequiredTitle">Choose your Portal identity</h2><button className="modal-close" type="button" onClick={onClose} aria-label="Close">×</button></div><p className="body-md">This is how people will recognise, mention and find you across Portal.</p><div className="form-actions"><a className="btn btn-primary" href="#/profile" onClick={onClose}>Create profile</a><button className="btn btn-secondary" type="button" onClick={onClose}>Not now</button></div></div></div>;
  function update(field, value) { setValues((current) => ({ ...current, [field]: value })); }
  function pickMedia(kind, file) {
    if (!file) return update(kind, null);
    const expected = kind === 'photo' ? 'image/' : 'video/';
    const limitMb = kind === 'photo' ? 25 : 100;
    if (!file.type.startsWith(expected) || file.size > limitMb * 1024 * 1024) { setError(`${kind === 'photo' ? 'Photos' : 'Videos'} must be a valid ${kind} under ${limitMb} MB.`); return; }
    setError(''); update(kind, file);
  }
  async function submit(event) {
    event.preventDefault();
    if (busy) return;
    if (values.title.trim().length < 3 || values.description.trim().length < 12 || (!values.eventId && values.eventTitle.trim().length < 3)) { setError('Give the report some substance, then attach it to an event or name the new happening.'); return; }
    setBusy(true); setError('');
    try { const record = await publishPortalReport(user, values, (kind, amount) => setProgress((current) => ({ ...current, [kind]: amount }))); onClose(); window.location.hash = `#/events/${record.eventId}`; } catch (reason) { setError(firebaseMessage(reason)); } finally { setBusy(false); }
  }
  return <div className="modal-overlay" role="dialog" aria-modal="true" aria-labelledby="createModalTitle" onMouseDown={onClose}><div className="modal form-modal report-modal" onMouseDown={(event) => event.stopPropagation()}><div className="modal-head"><div><h2 id="createModalTitle">Report a happening</h2><p className="body-sm">Give history something better than a vague group chat memory.</p></div><button className="modal-close" type="button" onClick={onClose} aria-label="Close">×</button></div>{error ? <p className="form-error" role="alert">{error}</p> : null}<form className="form-stack" onSubmit={submit}><label>Report title<input value={values.title} onChange={(event) => update('title', event.target.value)} maxLength="120" required /></label><label>What happened?<textarea value={values.description} onChange={(event) => update('description', event.target.value)} maxLength="2000" required /></label><div className="form-grid"><label>Location<input value={values.location} onChange={(event) => update('location', event.target.value)} maxLength="180" placeholder="Where it happened" /></label><label>Date and time<input type="datetime-local" value={values.occurredAt} onChange={(event) => update('occurredAt', event.target.value)} /></label></div><fieldset className="identity-mode"><legend>How should Portal frame this?</legend>{['Reporter', 'Casual'].map((mode) => <label key={mode}><input type="radio" name="identity" checked={values.identityMode === mode} onChange={() => update('identityMode', mode)} /> {mode}</label>)}</fieldset><label>Attach to an event<select value={values.eventId} onChange={(event) => update('eventId', event.target.value)}><option value="">Create a new event from this report</option>{events.map((item) => <option key={item.id} value={item.id}>{item.title}</option>)}</select></label>{!values.eventId ? <label>New event name<input value={values.eventTitle} onChange={(event) => update('eventTitle', event.target.value)} maxLength="120" placeholder="The happening this belongs to" required /></label> : null}<div className="form-grid media-inputs"><label>Photo evidence<input type="file" accept="image/*" onChange={(event) => pickMedia('photo', event.target.files?.[0])} /></label><label>Video evidence<input type="file" accept="video/*" onChange={(event) => pickMedia('video', event.target.files?.[0])} /></label></div>{values.photo || values.video ? <p className="body-sm">{values.photo?.name || ''}{values.photo && values.video ? ' · ' : ''}{values.video?.name || ''}{progress.photo ? ` · Photo ${progress.photo}%` : ''}{progress.video ? ` · Video ${progress.video}%` : ''}</p> : null}<div className="form-actions"><button className="btn btn-primary" disabled={busy}>{busy ? 'Publishing evidence...' : 'Publish report'}</button><button className="btn btn-secondary" type="button" onClick={onClose} disabled={busy}>Cancel</button></div></form></div></div>;
}

function PublicProfile({ handle }) {
  const [profile, setProfile] = useState(null); const [error, setError] = useState('');
  useEffect(() => { resolvePortalHandle(handle).then(setProfile).catch(() => setError('This Portal identity could not be found.')); }, [handle]);
  if (error) return <main className="auth-shell"><ErrorState message={error} /></main>;
  if (!profile) return <main className="auth-shell"><Loading label="Finding this Portal identity..." /></main>;
  return <main className="public-profile"><Brand /><section className="glass card"><Avatar size="lg">{initials(profile.displayName)}</Avatar><div><h1 className="display-xl">{profile.displayName || profile.handle}</h1><p className="profile-handle">@{profile.handle}</p>{profile.verificationState === 'verified' ? <span className="source-chip">Verified</span> : null}</div>{profile.bio ? <p className="body-md">{profile.bio}</p> : null}</section></main>;
}

function useRoute() { const routeValue = () => window.location.pathname.startsWith('/@') ? window.location.pathname : window.location.hash.replace('#', '') || '/'; const [route, setRoute] = useState(routeValue); useEffect(() => { const change = () => setRoute(routeValue()); window.addEventListener('hashchange', change); window.addEventListener('popstate', change); return () => { window.removeEventListener('hashchange', change); window.removeEventListener('popstate', change); }; }, []); return route; }

export function App() {
  const current = useRoute(); const [user, setUser] = useState(undefined); const [profile, setProfile] = useState(null); const [events, setEvents] = useState([]); const [eventsLoading, setEventsLoading] = useState(true); const [eventsError, setEventsError] = useState(''); const [vortexEntries, setVortexEntries] = useState([]); const [vortexLoading, setVortexLoading] = useState(true); const [vortexError, setVortexError] = useState(''); const [following, setFollowing] = useState(new Set()); const [posts, setPosts] = useState([]); const [echoedPostIds, setEchoedPostIds] = useState(new Set()); const [echoActivity, setEchoActivity] = useState([]); const [handlePurchases, setHandlePurchases] = useState([]); const [quotePost, setQuotePost] = useState(null); const [postComposerOpen, setPostComposerOpen] = useState(false); const [echoBusy, setEchoBusy] = useState(false); const [createOpen, setCreateOpen] = useState(false);
  useEffect(() => { if (!hasFirebaseConfig) { setUser(null); return undefined; } return observeSession(setUser); }, []);
  useEffect(() => { if (!user) return undefined; const stopProfile = observeProfile(user.uid, (snapshot) => setProfile(snapshot.exists() ? snapshot.data() : null)); const stopEvents = observeEvents((snapshot) => { setEvents(snapshot.docs.map((item) => ({ id: item.id, ...item.data() }))); setEventsLoading(false); }, (reason) => { setEventsError(firebaseMessage(reason)); setEventsLoading(false); }); const stopVortex = observeVortex(user.uid, (snapshot) => setFollowing(new Set(snapshot.docs.map((item) => item.id)))); const stopEntries = observeVortexEntries((snapshot) => { setVortexEntries(snapshot.docs.map((item) => item.data())); setVortexLoading(false); }, (reason) => { setVortexError(firebaseMessage(reason)); setVortexLoading(false); }); const stopPosts = observePublicPosts((snapshot) => setPosts(snapshot.docs.map((item) => ({ id: item.id, ...item.data() }))), () => setPosts([])); const stopPurchases = observeHandlePurchases(user.uid, (snapshot) => setHandlePurchases(snapshot.docs.map((item) => ({ id: item.id, ...item.data() }))), () => setHandlePurchases([])); const stopEchoes = observeUserEchoes(user.uid, (snapshot) => { const records = snapshot.docs.map((item) => ({ id: item.id, ...item.data() })); setEchoActivity(records); setEchoedPostIds(new Set(records.map((item) => item.sourcePostId))); }, () => { setEchoActivity([]); setEchoedPostIds(new Set()); }); return () => { stopProfile(); stopEvents(); stopVortex(); stopEntries(); stopPosts(); stopPurchases(); stopEchoes(); }; }, [user]);
  useEffect(() => { const accountRoutes = { '/settings': 'Settings', '/memory': 'Portal+ Memory', '/contributors': 'Contributor Hub', '/messages': 'Messages', '/sources': 'Official Sources' }; const route = current.startsWith('/events/') ? 'Event' : current.startsWith('/posts/') ? 'Post' : accountRoutes[current] || routes.concat(secondaryRoutes).find((item) => item.path === current)?.label || 'Home'; document.title = `${route} · Portal`; }, [current]);
  async function follow(eventId, next) { if (!user) return; await setVortexFollow(user.uid, eventId, next); }
  async function echo(postId, next) { if (!user || echoBusy) return; setEchoBusy(true); try { if (next) await echoPortalPost(postId); else await undoPortalEcho(postId); } catch (reason) { window.alert(firebaseMessage(reason)); } finally { setEchoBusy(false); } }
  async function quote(quoteText) { if (!quotePost || echoBusy) return; setEchoBusy(true); try { await createPortalQuoteEcho(quotePost.id, quoteText); setQuotePost(null); } catch (reason) { window.alert(firebaseMessage(reason)); } finally { setEchoBusy(false); } }
  async function publishPost(body) { if (echoBusy) return; setEchoBusy(true); try { await createPortalPost(body); setPostComposerOpen(false); } catch (reason) { window.alert(firebaseMessage(reason)); } finally { setEchoBusy(false); } }
  if (user === undefined) return <main className="auth-shell"><Loading label="Restoring your Portal session..." /></main>;
  if (current.startsWith('/@')) return <PublicProfile handle={current.slice(2)} />;
  if (!user) return <AuthScreen />;
  if (current === '/admin' || current.startsWith('/admin/')) return <AdminWorkspace current={current} />;
  const eventState = { events, loading: eventsLoading, error: eventsError };
  let page; if (current === '/events') page = <Events user={user} eventState={eventState} onFollow={follow} following={following} onCreate={() => setCreateOpen(true)} />; else if (current.startsWith('/events/')) page = <EventDetail eventId={current.split('/')[2]} user={user} events={events} onFollow={follow} following={following.has(current.split('/')[2])} />; else if (current.startsWith('/posts/')) page = <PostDetail postId={current.split('/')[2]} echoed={echoedPostIds.has(current.split('/')[2])} onEcho={echo} onQuote={setQuotePost} />; else if (current === '/notifications') page = <Notifications user={user} />; else if (current === '/messages') page = <FeaturePage title="Messages" description="Private Portal conversations will appear here when messaging opens." />; else if (current === '/sources') page = <FeaturePage title="Official Sources" description="Verified institutions, publishers and public sources connected to Portal Events." />; else if (current === '/memory') page = <FeaturePage title="Portal+ Memory" description="Your extended memory tools, accessible from Profile without crowding the primary navigation." />; else if (current === '/contributors') page = <FeaturePage title="Contributor Hub" description="Creator reporting tools and contributor context, kept inside Profile while the core network grows." />; else if (current === '/vortex') page = <Vortex entries={vortexEntries} loading={vortexLoading} error={vortexError} following={following} onFollow={follow} />; else if (current.startsWith('/marketplace')) page = <HandleMarketplace user={user} route={current} />; else if (current === '/settings') page = <Settings user={user} profile={profile} />; else if (current === '/profile') page = profile?.normalizedHandle ? <PersonalProfile user={user} profile={profile} posts={posts} echoActivity={echoActivity} handlePurchases={handlePurchases} echoedPostIds={echoedPostIds} onEcho={echo} onQuote={setQuotePost} /> : <ProfileSetup user={user} profile={profile} />; else if (current === '/custodians' || current === '/stewardship') page = <Custodians />; else page = <Home posts={posts} echoedPostIds={echoedPostIds} onEcho={echo} onQuote={setQuotePost} onCreatePost={() => setPostComposerOpen(true)} />;
  return <><a href="#main" className="skip-link">Skip to content</a><div className="app"><Sidebar current={current} onCreate={() => setCreateOpen(true)} /><Topbar profile={profile} /><div className="main-col"><main id="main" className="content-col" tabIndex="-1">{page}</main></div><BottomNav current={current} /></div><CreateModal open={createOpen} onClose={() => setCreateOpen(false)} user={user} profile={profile} events={events} />{quotePost ? <QuoteEchoComposer post={quotePost} onClose={() => setQuotePost(null)} onSubmit={quote} busy={echoBusy} /> : null}{postComposerOpen ? <PostComposer onClose={() => setPostComposerOpen(false)} onSubmit={publishPost} busy={echoBusy} /> : null}</>;
}
